{"tool":"newFileCreated","path":"frontend/src/components/Sidebar.jsx","content":"import React, { useState, useEffect } from 'react';
import { Activity, FileText, Wrench, Shield, Users, Calendar, LogOut, UserPlus, Clock, Package } from 'lucide-react';

const API = `${window.location.protocol}//${window.location.host}`;

const Sidebar = ({ user, activeTab, onTabChange, onLogout }) => {
  const [restingToday, setRestingToday] = useState([]);
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const fetchResting = async () => {
      try {
        const token = localStorage.getItem('token');
        const res = await fetch(`${API}/rest-days/today`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          setRestingToday(data);
        }
      } catch (e) {}
    };
    fetchResting();
    const interval = setInterval(fetching, 5000);
    const h = () => fetchResting();
    window.addEventListener('app-refresh', h);
    return () => { clearInterval(interval); window.removeEventListener('app-refresh', h); };
  }, []);

  const tabs = [
    { id: 'dashboard', label: 'Monitoring', icon: Activity, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'OPERATOR'] },
    { id: 'master', label: 'Master Panel', icon: Wrench, roles: ['ADMIN', 'MASTER'] },
    { id: 'nazoratchi', label: 'Nazoratchi', icon: Shield, roles: ['ADMIN', 'NAZORATCHI'] },
    { id: 'users', label: 'Foydalanuvchilar', icon: Users, roles: ['ADMIN', 'NAZORATCHI'] },
    { id: 'reports', label: 'Hisobotlar', icon: FileText, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
    { id: 'mechanic', label: 'Mexanik', icon: Package, roles: ['ADMIN', 'MASTER', 'OPERATOR'] },
    { id: 'attendance', label: 'Davomat', icon: Calendar, roles: ['ADMIN', 'MASTER'] },
    { id: 'schedule', label: 'Jadval', icon: Clock, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
  ];

  const filteredTabs = tabs.filter(t => t.roles.includes(user.role));

  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <h2>FazoLuxe</h2>
        <p className="sidebar-user">{user.full_name} ({user.role})</p>
      </div>
      <nav className="sidebar-nav">
        {filteredTabs.map(tab => (
          <button
            key={tab.id}
            className={`sidebar-tab ${activeTab === tab.id ? 'active' : ''}`}
            onClick={() => onTabChange(tab.id)}
          >
            <tab.icon size={18} />
            <span>{tab.label}</span>
          </button>
        ))}
      </nav>
      {restingToday.length > 0 && (
        <div className="sidebar-rest">
          <p className="rest-title">Bugun dam olish:</p>
          {restingToday.map(r => (
            <span key={r.operator_id} className="rest-name">{r.operator_name}</span>
          ))}
        </div>
      )}
      <div className="sidebar-footer">
        <div className="sidebar-time">
          {currentTime.toLocaleTimeString('uz-UZ')}
        </div>
        <button className="sidebar-logout" onClick={onLogout}>
          <LogOut size={16} />
          <span>Chiqish</span>
        </button>
      </div>
    </div>
  );
};

