                {shiftWorkers.length === 0 ? (
                  <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)', background: 'var(--card)', borderRadius: '16px', border: '1px solid var(--panel-border)' }}>
                    Ishchilar yo'q
                  </div>
