                  const blob = await res.blob();
                  const url = window.URL.createObjectURL(blob);
                  const a = document.createElement('a');
                  a.href = url; a.download = `tabel_${attendanceMonth}.xlsx`; a.click();
                  window.URL.revokeObjectURL(url);
                }
              } catch (e) {}
            }} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
              background: 'rgba(34,197,94,0.15)', color: '#22c55e', border: 'none', borderRadius: '10px',
              cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
            }}>
              <Download size={16} /> Excel
            </button>
          </div>

          <div style={tableCardStyle}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '800px' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                    <th style={{ ...thStyle, position: 'sticky', left: 0, background: '#1e293b', zIndex: 5, minWidth: '150px' }}>Ism</th>
                    {Array.from({ length: daysInMonth }, (_, i) => {
                      const d = i + 1;
                      const dateStr = `${attendanceMonth}-${String(d).padStart(2, '0')}`;
                      const isToday = dateStr === todayStr;
                      const dayOfWeek = new Date(dateStr).getDay();
                      const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
                      return (
                        <th key={d} style={{
                          ...thStyle, textAlign: 'center', padding: '8px 4px', minWidth: '36px',
                          background: isToday ? 'rgba(0,210,255,0.1)' : isWeekend ? 'rgba(245,158,11,0.05)' : '#1e293b',
